('proj-llm-eval-suite', 'ph-evaluation-safety', 91, 'project', NULL, NULL, NULL, 'Optional LLM Evaluation Suite', 'Optional practice project: Create regression tests for prompts, RAG answers, safety cases, and provider changes.', 'side', 10, 'advanced', '{"whatToBuild":"Create regression tests for prompts, RAG answers, safety cases, and provider changes.","buildSteps":["Define the LLM Evaluation Suite scenario and list the specific items to demonstrate: retrieval and citations.","Choose the dataset, model, prompt, retrieval source, or tool boundary required by the project brief.","Build the baseline workflow first, then add the AI/ML behavior in a way that can be inspected.","Capture evaluation cases that include successful output, weak output, and at least one failure mode.","Add safeguards, citations, metrics, traces, or manual review notes where the project context requires them.","Document model assumptions, limitations, cost/latency concerns, and what would need review before real use."],"source":"roadmap.sh/ai-engineer","nodeKey":"proj-llm-eval-suite"}'::jsonb, false, true, '["Apply Evaluation, Safety, and Guardrails through a focused LLM Evaluation Suite artifact.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a working LLM Evaluation Suite notebook, service, or app with evaluation notes is available for review.","The LLM Evaluation Suite scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness."]'::jsonb),
('ms-required-safety-eval', 'ph-evaluation-safety', 92, 'project', NULL, NULL, NULL, 'Required AI Safety and Evaluation Project', 'Capstone project: Add evals, prompt-injection tests, safety policies, and traceable guardrails to a real AI app.', 'side', 14, 'advanced', '{"whatToBuild":"Add evals, prompt-injection tests, safety policies, and traceable guardrails to a real AI app.","buildSteps":["Define the AI Safety and Evaluation Project scenario and list the specific items to demonstrate: prompt versions and outputs.","Choose the dataset, model, prompt, retrieval source, or tool boundary required by the project brief.","Build the baseline workflow first, then add the AI/ML behavior in a way that can be inspected.","Capture evaluation cases that include successful output, weak output, and at least one failure mode.","Add safeguards, citations, metrics, traces, or manual review notes where the project context requires them.","Document model assumptions, limitations, cost/latency concerns, and what would need review before real use.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim.","Document how to run or review the AI Safety and Evaluation Project deliverable, including inputs, expected outputs, and known limitations."],"source":"roadmap.sh/ai-engineer","nodeKey":"ms-required-safety-eval"}'::jsonb, true, true, '["Apply Evaluation, Safety, and Guardrails through a focused AI Safety and Evaluation Project artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The an working AI Safety and Evaluation Project notebook, service, or app with evaluation notes is available for review.","The AI Safety and Evaluation Project scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb),
('chk-eval-safety-review', 'ph-evaluation-safety', 99, 'checkpoint', 'assessment', NULL, NULL, 'Evaluation and Safety Review', 'Review checkpoint for Evaluation, Safety, and Guardrails. The learner synthesizes completed topics such as Golden Datasets, Assertion-Based Tests, LLM-as-Judge Cautions, Pairwise Comparison, records evidence, and updates the learning plan before continuing.', 'checkpoint', 2, 'advanced', '{"reviewFocus":"Review checkpoint for Evaluation, Safety, and Guardrails. The learner synthesizes completed topics such as Golden Datasets, Assertion-Based Tests, LLM-as-Judge Cautions, Pairwise Comparison, records evidence, and updates the learning plan before continuing.","reviewCriteria":["Write a concise review of the main ideas from this segment.","Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.","Record open questions, weak areas, or follow-up actions.","Mark the checkpoint complete only after the review artifact and next steps are captured."],"source":"roadmap.sh/ai-engineer","nodeKey":"chk-eval-safety-review"}'::jsonb, true, true, '["Explain how topics from Evaluation, Safety, and Guardrails connect to realistic AI engineering work.", "Select evidence that shows attempted practice, reasoning, or implementation decisions.", "Identify which topics need review before moving to later roadmap areas."]'::jsonb, '["Write a concise review of the main ideas from this segment.", "Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.", "Record open questions, weak areas, or follow-up actions.", "Mark the checkpoint complete only after the review artifact and next steps are captured."]'::jsonb),
